    index index.html;

    # --- OS-level file serving optimizations ---
    sendfile       on;   # Use kernel sendfile() to avoid user-space copy
    tcp_nopush     on;   # Batch response headers + file start in one packet (requires sendfile)
    tcp_nodelay    on;   # Disable Nagle's algorithm for faster small packet delivery

    # --- File descriptor cache (avoids repeated stat() on every request) ---
    open_file_cache          max=1000 inactive=20s;
    open_file_cache_valid    30s;
    open_file_cache_min_uses 2;
    open_file_cache_errors   on;

    # --- Logging ---
    # error_log is always useful for diagnosing 502s, permission issues, etc.
    error_log /var/log/nginx/amytis.error.log warn;
    # access_log generates significant I/O on busy sites. If you use an
    # analytics tool (e.g. Umami), consider setting this to off.
    # Buffering writes reduces disk pressure when keeping it enabled.
    access_log /var/log/nginx/amytis.access.log combined buffer=16k flush=5s;

    # --- Compression ---
    gzip on;
    gzip_vary on;
    gzip_proxied any;
    gzip_comp_level 6;
    gzip_min_length 1024;
    gzip_types
        text/css
        text/plain
        application/javascript
        application/json
        application/xml
        image/svg+xml
        font/woff;
        # Note: WOFF2 is already Brotli-compressed internally — gzipping it adds
        # CPU overhead with no size benefit, so it is intentionally excluded.

    # --- Security + HSTS ---
    # HSTS: browsers skip the HTTP→HTTPS redirect on repeat visits (1 year).
    # Only enable includeSubDomains if ALL subdomains serve HTTPS.
    # NOTE: Nginx add_header in a location block does NOT inherit server-level
    # add_header directives. Security headers must be repeated in every location
    # block that sets its own add_header, otherwise they are silently dropped.
    add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header X-Frame-Options "SAMEORIGIN" always;

    # --- Cache: Next.js static assets (content-hashed → cache forever) ---
    location /_next/static/ {
        add_header Cache-Control "public, max-age=31536000, immutable";
        add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
        add_header X-Content-Type-Options "nosniff" always;
        add_header X-Frame-Options "SAMEORIGIN" always;
        access_log off;
    }

    # --- Cache: images and fonts ---
    location ~* \.(webp|png|jpg|jpeg|gif|ico|svg|woff2|woff|ttf)$ {
        add_header Cache-Control "public, max-age=86400";
        add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
        add_header X-Content-Type-Options "nosniff" always;
        add_header X-Frame-Options "SAMEORIGIN" always;
        access_log off;
    }

    # --- Cache: feed files (short TTL so readers see new posts quickly) ---
    location ~* \.(xml|atom)$ {
        add_header Cache-Control "public, max-age=3600";
        add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
        add_header X-Content-Type-Options "nosniff" always;
        add_header X-Frame-Options "SAMEORIGIN" always;
    }

    # --- HTML pages: no cache (always fresh) ---
    location ~* \.html$ {
        add_header Cache-Control "no-cache";
        add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
        add_header X-Content-Type-Options "nosniff" always;
        add_header X-Frame-Options "SAMEORIGIN" always;
    }

    # --- Feed shortcuts ---
    # Redirect bare /feed and /atom (with or without trailing slash) to the
    # canonical file URLs so RSS readers and users who omit the extension work.
    location ~ ^/feed/?$ { return 301 /feed.xml; }
    location ~ ^/atom/?$ { return 301 /feed.atom; }

    # --- Static file serving ---
    # next.config.ts uses trailingSlash: true, so pages export as slug/index.html.
    # Nginx strips the trailing slash from the visible URL so browsers show /slug
    # instead of /slug/. Client-side navigation is handled by the JS router and
    # never hits Nginx, so the redirect has no cost for in-app link clicks.
    autoindex off;

    # Redirect /slug/ → /slug (removes trailing slash from visible URL)
    location ~ ^(.+)/$ {
        return 301 $1;
    }

    location / {
        # $uri/index.html serves the trailingSlash: true export for clean /slug URLs
        try_files $uri $uri/index.html =404;
    }

    # --- SSL certificates (e.g. Let's Encrypt) ---
    ssl_certificate     /etc/letsencrypt/live/example.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/example.com/privkey.pem;

    # --- OCSP stapling (Nginx pre-fetches cert revocation status so browsers don't have to) ---
    ssl_stapling        on;
    ssl_stapling_verify on;
    ssl_trusted_certificate /etc/letsencrypt/live/example.com/chain.pem;
    resolver 1.1.1.1 8.8.8.8 valid=300s;
    resolver_timeout 5s;

    # --- TLS hardening ---
    ssl_protocols TLSv1.2 TLSv1.3;
    # Mozilla intermediate cipher list (broad compatibility, no known-weak ciphers)
    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384:ECDHE-ECDSA-CHACHA20-POLY1305:ECDHE-RSA-CHACHA20-POLY1305:DHE-RSA-AES128-GCM-SHA256:DHE-RSA-AES256-GCM-SHA384;
    ssl_prefer_server_ciphers on;  # Enforces order above for TLS 1.2; no-op for TLS 1.3

    # --- SSL session resumption (avoids repeat full handshakes) ---
    ssl_session_cache   shared:SSL:10m;  # ~40k sessions shared across workers
    ssl_session_timeout 1d;

    # --- Keep connections alive across multiple requests ---
    keepalive_timeout 65;
}

